    88→interface KanbanStore extends KanbanState {
    89→  // Existing task actions
    90→  addTask: (task: Omit<Task, 'id' | 'created'>) => void;
    91→  updateTask: (id: string, updates: Partial<Task>) => void;
    92→  deleteTask: (id: string) => void;
    93→  moveTask: (id: string, newStatus: TaskStatus) => void;
    94→  getTasksByStatus: (status: TaskStatus) => Task[];
    95→
    96→  // P1: Recurring tasks
    97→  setTaskRecurrence: (taskId: string, recurrence: Task['recurrence']) => void;
    98→  generateNextRecurringInstance: (parentTaskId: string) => void;
    99→  getRecurringTaskInstances: (parentTaskId: string) => Task[];
   100→
   101→  // Phase 4: Column management
   102→  addColumn: (column: Omit<KanbanColumn, 'id' | 'order'>) => void;
   103→  updateColumn: (id: string, updates: Partial<KanbanColumn>) => void;
   104→  deleteColumn: (id: string) => void;
   105→  reorderColumns: (columnIds: string[]) => void;
   106→  replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => void;
   107→
   108→  // Phase 4: Checklist management
   109→  addChecklistItem: (taskId: string, text: string) => void;
   110→  updateChecklistItem: (taskId: string, itemId: string, updates: Partial<ChecklistItem>) => void;
   111→  deleteChecklistItem: (taskId: string, itemId: string) => void;
   112→  toggleChecklistItem: (taskId: string, itemId: string) => void;
   113→  reorderChecklistItems: (taskId: string, itemIds: string[]) => void;
   114→
   115→  // Phase 4: Comment management
   116→  addComment: (taskId: string, text: string) => void;
   117→  updateComment: (taskId: string, commentId: string, text: string) => void;
   118→  deleteComment: (taskId: string, commentId: string) => void;
   119→
   120→  // Phase 4: Activity log (auto-tracked)
   121→  logActivity: (taskId: string, entry: Omit<ActivityLogEntry, 'id' | 'timestamp'>) => void;
   122→
   123→  // Phase 4: Bulk actions
   124→  bulkUpdateStatus: (taskIds: string[], newStatus: TaskStatus) => void;
   125→  bulkUpdatePriority: (taskIds: string[], newPriority: TaskPriority) => void;
   126→  bulkDeleteTasks: (taskIds: string[]) => void;
   127→
   128→  // Phase 5: Subtask management
   129→  addSubtask: (taskId: string, subtaskData: Omit<Subtask, 'id' | 'parentTaskId' | 'createdAt' | 'order'>) => void;
   130→  updateSubtask: (taskId: string, subtaskId: string, updates: Partial<Subtask>) => void;
   131→  deleteSubtask: (taskId: string, subtaskId: string) => void;
   132→  toggleSubtask: (taskId: string, subtaskId: string) => void;
   133→  reorderSubtasks: (taskId: string, subtaskIds: string[]) => void;
   134→
   135→  // Phase 5: Dependency management
   136→  addDependency: (sourceTaskId: string, targetTaskId: string) => void;
   137→  removeDependency: (dependencyId: string) => void;
   138→  getBlockers: (taskId: string) => Task[];
   139→  getBlocked: (taskId: string) => Task[];
   140→
   141→  // Phase A: Archive management
   142→  archiveTask: (id: string) => void;
   143→  restoreTask: (id: string) => void;
   144→  deleteArchivedTask: (id: string) => void;
   145→  getArchivedTasks: () => Task[];
   146→  autoArchiveCompletedTasks: () => void;
   147→
   148→  // Phase B: Time tracking
   149→  startTimer: (taskId: string) => void;
   150→  stopTimer: (taskId: string) => void;
   151→  updateTimeEstimate: (taskId: string, hours: number) => void;
   152→
   153→  // Phase B: Custom fields
   154→  updateEffort: (taskId: string, effort: import('../types').EffortEstimate | undefined) => void;
   155→  updateCustomStatus: (taskId: string, customStatus: import('../types').CustomStatus | undefined) => void;
   156→
   157→  // Bulk import
   158→  bulkImportTasks: (importedTasks: Array<{
   159→    title: string;
   160→    description?: string;
   161→    dueDate?: string;
   162→    priority?: TaskPriority;
   163→    tags?: string[];
   164→    status?: TaskStatus;
   165→    completed?: boolean;
   166→    estimatedHours?: number;
   167→    progress?: number;
   168→    checklist?: Array<{ text: string; completed: boolean }>;
   169→  }>) => import('../types/import').ImportResult;
   170→
   171→  // UI Preferences
   172→  setVisibleColumns: (count: number) => void;
   173→
   174→  // Undo system
