   183→
   184→export const useKanbanStore = create<KanbanStore>()(
   185→  persist(
   186→    (set, get) => ({
   187→      // Initial state
   188→      tasks: [],
   189→      columns: DEFAULT_COLUMNS,
   190→      dependencies: [], // Phase 5: Task dependencies
   191→      archivedTasks: [], // Phase A: Archived tasks
   192→      nextCardNumber: 1, // Phase A: Auto-incrementing card number counter
   193→      visibleColumns: 5, // UI: Number of columns visible before scrolling (default: 5)
   194→      undoHistory: [], // Undo system: stores last 5 actions
   195→
   196→      // ==================== TASK ACTIONS ====================
   197→
   198→      addTask: (taskData) => {
   199→        const currentNumber = get().nextCardNumber || 1;
   200→
   201→        const newTask: Task = {
   202→          ...taskData,
   203→          id: Date.now().toString(),
   204→          created: new Date().toISOString(),
   205→          cardNumber: currentNumber, // Phase A: Assign auto-incrementing card number
   206→          checklist: [],
   207→          comments: [],
   208→          activityLog: [],
   209→        };
   210→
   211→        set((state) => ({
   212→          tasks: [...state.tasks, newTask],
   213→          nextCardNumber: currentNumber + 1, // Increment counter
   214→        }));
   215→
   216→        // Log creation
   217→        get().logActivity(newTask.id, {
   218→          action: 'created',
   219→        });
   220→
   221→        // P1: Trigger automation rules for 'task.created'
   222→        setTimeout(async () => {
   223→          const { useAutomationStore } = await import('./useAutomationStore');
   224→          const automationStore = useAutomationStore.getState();
   225→          const context: AutomationContext = {
   226→            taskId: newTask.id,
   227→            timestamp: new Date().toISOString(),
   228→          };
   229→
   230→          const logs = await evaluateRules(
   231→            automationStore.rules,
   232→            'task.created',
   233→            newTask,
   234→            context,
   235→            get()
   236→          );
   237→          logs.forEach((log) => automationStore.addExecutionLog(log));
   238→        }, 0);
   239→      },
   240→
   241→      updateTask: (id, updates) => {
   242→        const oldTask = get().tasks.find((t) => t.id === id);
   243→        if (!oldTask) return;
   244→
   245→        set((state) => ({
   246→          tasks: state.tasks.map((task) =>
   247→            task.id === id ? { ...task, ...updates } : task
   248→          ),
   249→        }));
   250→
   251→        // Log updates (track specific fields)
   252→        Object.keys(updates).forEach((field) => {
   253→          if (field !== 'activityLog') { // Don't log the log itself
   254→            get().logActivity(id, {
   255→              action: 'updated',
   256→              field,
   257→              oldValue: String(oldTask[field as keyof Task] ?? ''),
   258→              newValue: String(updates[field as keyof Task] ?? ''),
   259→            });
   260→          }
   261→        });
   262→      },
   263→
   264→      deleteTask: (id) =>
   265→        set((state) => ({
   266→          tasks: state.tasks.filter((task) => task.id !== id),
   267→        })),
   268→
   269→      moveTask: (id, newStatus) => {
   270→        const oldTask = get().tasks.find((t) => t.id === id);
   271→        if (!oldTask) return;
   272→
   273→        // PHASE 5 PART 6: Validate dependencies before moving to "done"
   274→        if (newStatus === 'done') {
   275→          const blockers = get().getBlockers(id);
   276→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   277→
   278→          if (incompleteBlockers.length > 0) {
   279→            log.warn('Cannot complete task: blocked by incomplete tasks', {
   280→              taskId: id,
   281→              taskTitle: oldTask.title,
   282→              blockerCount: incompleteBlockers.length
   283→            });
   284→            // TODO: Show toast notification in UI
   285→            return; // Prevent move
   286→          }
   287→        }
   288→
   289→        // PHASE A: Track when task is completed (for auto-archive)
   290→        const updates: Partial<Task> = { status: newStatus };
   291→        if (newStatus === 'done' && oldTask.status !== 'done') {
   292→          updates.lastCompletedAt = new Date().toISOString();
   293→        }
   294→
   295→        // P1: AUTO-GENERATE NEXT RECURRING INSTANCE
   296→        // If completing a recurring task instance, generate next occurrence
   297→        const isCompletingRecurringInstance = newStatus === 'done' && oldTask.recurrenceId;
   298→
   299→        set((state) => ({
   300→          tasks: state.tasks.map((task) =>
   301→            task.id === id ? { ...task, ...updates } : task
   302→          ),
   303→        }));
   304→
   305→        // Generate next instance after state update (avoid mutation during update)
   306→        if (isCompletingRecurringInstance) {
   307→          setTimeout(() => {
   308→            get().generateNextRecurringInstance(oldTask.recurrenceId!);
   309→          }, 0);
   310→        }
   311→
   312→        // Log move
   313→        get().logActivity(id, {
   314→          action: 'moved',
   315→          field: 'status',
   316→          oldValue: oldTask.status,
   317→          newValue: newStatus,
   318→        });
   319→
   320→        // P1: Trigger automation rules for 'task.moved' and potentially 'task.completed'
   321→        setTimeout(async () => {
   322→          const { useAutomationStore } = await import('./useAutomationStore');
   323→          const automationStore = useAutomationStore.getState();
   324→          const updatedTask = get().tasks.find((t) => t.id === id);
   325→          if (!updatedTask) return;
   326→
   327→          const context: AutomationContext = {
   328→            taskId: id,
   329→            previousStatus: oldTask.status,
   330→            newStatus,
   331→            timestamp: new Date().toISOString(),
   332→          };
   333→
   334→          // Trigger 'task.moved' for all status changes
   335→          const movedLogs = await evaluateRules(
   336→            automationStore.rules,
   337→            'task.moved',
   338→            updatedTask,
   339→            context,
   340→            get()
   341→          );
   342→          movedLogs.forEach((log) => automationStore.addExecutionLog(log));
   343→
   344→          // Also trigger 'task.completed' if moved to done
   345→          if (newStatus === 'done') {
   346→            const completedLogs = await evaluateRules(
   347→              automationStore.rules,
   348→              'task.completed',
   349→              updatedTask,
   350→              context,
   351→              get()
   352→            );
   353→            completedLogs.forEach((log) => automationStore.addExecutionLog(log));
   354→          }
   355→        }, 0);
   356→      },
   357→
   358→      getTasksByStatus: (status) => {
   359→        return get().tasks.filter((task) => task.status === status);
   360→      },
   361→
   362→      // ==================== RECURRING TASK ACTIONS (P1) ====================
   363→
   364→      setTaskRecurrence: (taskId, recurrence) => {
   365→        const task = get().tasks.find((t) => t.id === taskId);
   366→        if (!task) {
   367→          log.warn('Task not found for recurrence', { taskId });
   368→          return;
   369→        }
   370→
   371→        // Mark as recurring parent and calculate next occurrence
   372→        const updates: Partial<Task> = {
   373→          recurrence,
   374→          isRecurringParent: recurrence ? true : undefined,
   375→          nextOccurrence: recurrence ? updateNextOccurrence({ ...task, recurrence }) : undefined,
   376→        };
   377→
   378→        get().updateTask(taskId, updates);
   379→
   380→        log.info('Task recurrence set', { taskId, frequency: recurrence?.frequency });
   381→      },
   382→
   383→      generateNextRecurringInstance: (parentTaskId) => {
   384→        const parentTask = get().tasks.find((t) => t.id === parentTaskId);
   385→        if (!parentTask || !parentTask.isRecurringParent) {
   386→          log.warn('Not a recurring parent task', { parentTaskId });
   387→          return;
   388→        }
   389→
   390→        // Check if we should generate next instance
   391→        if (!shouldGenerateNextInstance(parentTask, get().tasks)) {
   392→          log.debug('Next instance not needed yet', { parentTaskId });
   393→          return;
   394→        }
   395→
   396→        // Generate new instance
   397→        const instance = generateNextInstance(parentTask);
   398→        if (!instance) {
   399→          log.debug('No more instances to generate (series ended)', { parentTaskId });
   400→          return;
   401→        }
   402→
   403→        // Add instance to tasks
   404→        set((state) => ({
   405→          tasks: [...state.tasks, instance],
   406→        }));
   407→
   408→        // Update parent's nextOccurrence
   409→        const nextOccurrence = updateNextOccurrence(parentTask);
   410→        get().updateTask(parentTaskId, { nextOccurrence });
   411→
   412→        log.info('Generated recurring task instance', {
   413→          parentId: parentTaskId,
   414→          instanceId: instance.id,
   415→          dueDate: instance.dueDate,
   416→        });
   417→      },
   418→
   419→      getRecurringTaskInstances: (parentTaskId) => {
   420→        return getTaskInstances(
   421→          get().tasks.find((t) => t.id === parentTaskId)!,
   422→          get().tasks
   423→        );
   424→      },
   425→
   426→      // ==================== COLUMN ACTIONS ====================
   427→
   428→      addColumn: (columnData) => {
   429→        const columns = get().columns;
   430→        const newColumn: KanbanColumn = {
   431→          ...columnData,
   432→          id: `col-${Date.now()}`,
   433→          order: columns.length,
   434→        };
   435→
   436→        set((state) => ({
   437→          columns: [...state.columns, newColumn],
   438→        }));
   439→      },
   440→
   441→      updateColumn: (id, updates) => {
   442→        set((state) => ({
   443→          columns: state.columns.map((col) =>
   444→            col.id === id ? { ...col, ...updates } : col
   445→          ),
   446→        }));
   447→      },
   448→
   449→      deleteColumn: (id) => {
   450→        const state = get();
   451→        const columnToDelete = state.columns.find(col => col.id === id);
   452→
   453→        if (!columnToDelete) {
   454→          log.warn('Column not found for deletion', { columnId: id });
   455→          return;
   456→        }
   457→
   458→        // Save undo entry BEFORE making changes
   459→        get().addToUndoHistory({
   460→          action: 'deleteColumn',
   461→          description: `Deleted column '${columnToDelete.title}'`,
   462→          previousState: {
   463→            columns: state.columns,
   464→            tasks: state.tasks,
   465→          },
   466→        });
   467→
   468→        // Find first remaining column (fallback, not hardcoded 'backlog')
   469→        const firstRemainingColumn = state.columns.find(col => col.id !== id);
   470→
   471→        if (!firstRemainingColumn) {
   472→          log.error('Cannot delete last column');
   473→          return;
   474→        }
   475→
   476→        // Move all tasks from deleted column to first remaining column
   477→        set((state) => ({
   478→          columns: state.columns.filter((col) => col.id !== id),
   479→          tasks: state.tasks.map((task) =>
   480→            task.status === id as TaskStatus
   481→              ? { ...task, status: firstRemainingColumn.id as TaskStatus }
   482→              : task
   483→          ),
   484→        }));
   485→      },
   486→
   487→      reorderColumns: (columnIds) => {
   488→        const columns = get().columns;
   489→        const reordered = columnIds
   490→          .map((id) => columns.find((col) => col.id === id))
   491→          .filter((col): col is KanbanColumn => col !== undefined)
   492→          .map((col, index) => ({ ...col, order: index }));
   493→
   494→        set({ columns: reordered });
   495→      },
   496→
   497→      replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => {
   498→        const state = get();
   499→
   500→        // Save undo entry BEFORE making changes
   501→        get().addToUndoHistory({
   502→          action: 'replaceAllColumns',
   503→          description: `Applied template`,
   504→          previousState: {
   505→            columns: state.columns,
   506→            tasks: state.tasks,
   507→          },
   508→        });
   509→
   510→        // Generate new columns with fresh IDs and correct order
   511→        const columns: KanbanColumn[] = newColumns.map((col, index) => ({
   512→          ...col,
   513→          id: `col-${Date.now()}-${index}`,
   514→          order: index,
   515→        }));
   516→
   517→        if (columns.length === 0) {
   518→          log.error('No columns provided for replacement');
   519→          return;
   520→        }
   521→
   522→        // Smart mapping: Try to preserve task positions based on column titles
   523→        const tasks = state.tasks.map(task => {
   524→          const oldColumn = state.columns.find(c => c.id === task.status);
   525→          if (!oldColumn) {
   526→            // Task has invalid status, move to first column
   527→            return { ...task, status: columns[0].id as TaskStatus };
   528→          }
   529→
   530→          // Try exact match first (case-insensitive)
   531→          let newColumn = columns.find(c =>
   532→            c.title.toLowerCase() === oldColumn.title.toLowerCase()
   533→          );
   534→
   535→          // If no exact match, try partial match (contains)
   536→          if (!newColumn) {
   537→            newColumn = columns.find(c =>
   538→              c.title.toLowerCase().includes(oldColumn.title.toLowerCase()) ||
   539→              oldColumn.title.toLowerCase().includes(c.title.toLowerCase())
   540→            );
   541→          }
   542→
   543→          // Fallback: first column
   544→          if (!newColumn) {
   545→            newColumn = columns[0];
   546→          }
   547→
   548→          return { ...task, status: newColumn.id as TaskStatus };
   549→        });
   550→
   551→        set({ columns, tasks });
   552→      },
   553→
   554→      // ==================== CHECKLIST ACTIONS ====================
   555→
   556→      addChecklistItem: (taskId, text) => {
   557→        const task = get().tasks.find((t) => t.id === taskId);
   558→        if (!task) return;
   559→
   560→        const newItem: ChecklistItem = {
   561→          id: `check-${Date.now()}`,
   562→          text,
   563→          completed: false,
   564→          order: (task.checklist || []).length,
   565→          createdAt: new Date().toISOString(),
   566→        };
   567→
   568→        set((state) => ({
   569→          tasks: state.tasks.map((t) =>
   570→            t.id === taskId
   571→              ? { ...t, checklist: [...(t.checklist || []), newItem] }
   572→              : t
   573→          ),
   574→        }));
   575→
   576→        // Log checklist update
   577→        get().logActivity(taskId, {
   578→          action: 'checklist_updated',
   579→          newValue: `Added: ${text}`,
   580→        });
   581→      },
   582→
   583→      updateChecklistItem: (taskId, itemId, updates) => {
   584→        set((state) => ({
   585→          tasks: state.tasks.map((t) =>
   586→            t.id === taskId
   587→              ? {
   588→                  ...t,
   589→                  checklist: (t.checklist || []).map((item) =>
   590→                    item.id === itemId ? { ...item, ...updates } : item
   591→                  ),
   592→                }
   593→              : t
   594→          ),
   595→        }));
   596→      },
   597→
   598→      deleteChecklistItem: (taskId, itemId) => {
   599→        const task = get().tasks.find((t) => t.id === taskId);
   600→        if (!task) return;
   601→
   602→        const item = task.checklist?.find((i) => i.id === itemId);
   603→        if (!item) return;
   604→
   605→        set((state) => ({
   606→          tasks: state.tasks.map((t) =>
   607→            t.id === taskId
   608→              ? {
   609→                  ...t,
   610→                  checklist: (t.checklist || []).filter((i) => i.id !== itemId),
   611→                }
   612→              : t
   613→          ),
   614→        }));
   615→
   616→        // Log deletion
   617→        get().logActivity(taskId, {
   618→          action: 'checklist_updated',
   619→          oldValue: `Removed: ${item.text}`,
   620→        });
   621→      },
   622→
   623→      toggleChecklistItem: (taskId, itemId) => {
   624→        const task = get().tasks.find((t) => t.id === taskId);
