  1030→        const wouldCreateCycle = (source: string, target: string): boolean => {
  1031→          if (source === target) return true;
  1032→          const childDeps = dependencies.filter((d) => d.sourceTaskId === target);
  1033→          return childDeps.some((d) => wouldCreateCycle(source, d.targetTaskId));
  1034→        };
  1035→
  1036→        if (wouldCreateCycle(sourceTaskId, targetTaskId)) {
  1037→          log.error('Circular dependency detected', { sourceTaskId, targetTaskId });
  1038→          return;
  1039→        }
  1040→
  1041→        const newDependency: SimpleTaskDependency = {
