     1→/**
     2→ * Custom Fields Type Definitions
     3→ *
     4→ * Defines types for custom field system that allows users to add
     5→ * structured metadata to tasks and notes beyond default fields.
     6→ */
     7→
     8→/**
     9→ * Supported custom field types
    10→ */
    11→export type FieldType = 'text' | 'number' | 'date' | 'select' | 'checkbox';
    12→
    13→/**
    14→ * Field definition - describes a custom field's schema
    15→ */
    16→export interface FieldDefinition {
    17→  /** Unique identifier for the field */
    18→  id: string;
    19→  /** Display name of the field */
    20→  name: string;
    21→  /** Field data type */
    22→  type: FieldType;
    23→  /** Default value when field is added to a task/note */
    24→  defaultValue?: any;
    25→  /** For 'select' type: list of allowed options */
    26→  options?: string[];
    27→  /** Whether this field is required */
    28→  required?: boolean;
    29→  /** Optional description/help text */
    30→  description?: string;
    31→  /** Timestamp when field was created */
    32→  createdAt: Date;
    33→  /** Timestamp when field was last modified */
    34→  updatedAt: Date;
    35→}
    36→
    37→/**
    38→ * Custom field value instance
    39→ */
    40→export interface CustomFieldValue {
    41→  /** ID of the field definition this value corresponds to */
    42→  fieldId: string;
    43→  /** Actual value (type varies based on field.type) */
    44→  value: any;
    45→}
